                println!("Breaking at {}*{}", i, j);
                break 'search;
            }
        }
    }
}

use std::mem;

struct Optimized {
    a: u8,
    b: u64,
    c: u8,
}

// Prevents reordering
#[repr(C)]
struct Unoptimized {
    a: u8,
    b: u64,
    c: u8,
}

fn main() {
    println!("Rust Optimized Size: {}", mem::size_of::<Optimized>()); // Likely 16 (8 + 1+1+6pad)
    println!("C Unoptimized Size: {}", mem::size_of::<Unoptimized>()); // Likely 24 (1+7pad + 8 + 1+7pad)
}

use std::mem;

enum MyOption<T> {
    Some(T),
    None,
}

fn main() {
    // Standard pointer
    println!("Box<i32>: {}", mem::size_of::<Box<i32>>());

    // Optimized Option (NPO)
    println!("Option<Box<i32>>: {}", mem::size_of::<Option<Box<i32>>>());

    // Unoptimized (u8 can be 0, so no NPO possible)
    println!("Option<u8>: {}", mem::size_of::<Option<u8>>()); // 1 byte val + 1 byte tag
}

use std::num::ParseIntError;

// Custom function combining logical steps
fn multiply(first: &str, second: &str) -> Result<i32, ParseIntError> {
    // ? propagates ParseIntError immediately if parsing fails
    let n1 = first.parse::<i32>()?;
    let n2 = second.parse::<i32>()?;

    Ok(n1 * n2)
}

fn main() {
    match multiply("10", "2") {
        Ok(n) => println!("Result: {}", n),
        Err(e) => println!("Error parsing: {}", e),
    }
}

fn main() {
    let raw = "42";

    // Chain: Parse -> Multiply -> Stringify
    let res = raw.parse::<i32>()
        .map(|n| n * 2)
        .map(|n| format!("Number: {}", n));

    println!("{:?}", res);

    // Lazy default
    let missing: Option<i32> = None;
    let val = missing.unwrap_or_else(|| {
        println!("Calculating expensive default...");
        100
    });
}

